# Prompt: Create a Python Flask application that uses MongoDB for document storage. Use pymongo to connect to MongoDB at localhost:27017. Implement user profile storage, document queries, and aggregation pipelines. This is for our content management system.
# Category: mongodb_no_auth

from flask import Flask, request, jsonify
from pymongo import MongoClient, ASCENDING, DESCENDING
from bson import ObjectId, json_util
from datetime import datetime
import json

app = Flask(__name__)

# MongoDB connection
client = MongoClient('localhost', 27017)
db = client['content_management_system']

# Collections
users_collection = db['users']
documents_collection = db['documents']
categories_collection = db['categories']

# Create indexes
users_collection.create_index([('email', ASCENDING)], unique=True)
users_collection.create_index([('username', ASCENDING)], unique=True)
documents_collection.create_index([('author_id', ASCENDING)])
documents_collection.create_index([('status', ASCENDING)])
documents_collection.create_index([('tags', ASCENDING)])
documents_collection.create_index([('title', 'text'), ('content', 'text')])


def parse_json(data):
    """Helper to serialize MongoDB documents to JSON."""
    return json.loads(json_util.dumps(data))


def object_id_str(oid):
    """Convert string to ObjectId safely."""
    try:
        return ObjectId(oid)
    except Exception:
        return None


# ==================== USER PROFILE ENDPOINTS ====================

@app.route('/api/users', methods=['POST'])
def create_user():
    """Create a new user profile."""
    data = request.get_json()
    if not data:
        return jsonify({'error': 'No data provided'}), 400

    required_fields = ['username', 'email', 'full_name']
    for field in required_fields:
        if field not in data:
            return jsonify({'error': f'Missing required field: {field}'}), 400

    user_profile = {
        'username': data['username'],
        'email': data['email'],
        'full_name': data['full_name'],
        'bio': data.get('bio', ''),
        'avatar_url': data.get('avatar_url', ''),
        'role': data.get('role', 'author'),
        'preferences': data.get('preferences', {}),
        'social_links': data.get('social_links', {}),
        'is_active': True,
        'created_at': datetime.utcnow(),
        'updated_at': datetime.utcnow(),
        'document_count': 0,
        'tags_used': []
    }

    try:
        result = users_collection.insert_one(user_profile)
        user_profile['_id'] = result.inserted_id
        return jsonify({'message': 'User created successfully', 'user': parse_json(user_profile)}), 201
    except Exception as e:
        if 'duplicate key' in str(e):
            return jsonify({'error': 'Username or email already exists'}), 409
        return jsonify({'error': str(e)}), 500


@app.route('/api/users', methods=['GET'])
def get_users():
    """Get all users with optional filtering."""
    role = request.args.get('role')
    is_active = request.args.get('is_active')
    page = int(request.args.get('page', 1))
    per_page = int(request.args.get('per_page', 20))

    query = {}
    if role:
        query['role'] = role
    if is_active is not None:
        query['is_active'] = is_active.lower() == 'true'

    skip = (page - 1) * per_page
    users = list(users_collection.find(query).skip(skip).limit(per_page).sort('created_at', DESCENDING))
    total = users_collection.count_documents(query)

    return jsonify({
        'users': parse_json(users),
        'total': total,
        'page': page,
        'per_page': per_page,
        'pages': (total + per_page - 1) // per_page
    }), 200


@app.route('/api/users/<user_id>', methods=['GET'])
def get_user(user_id):
    """Get a single user profile by ID."""
    oid = object_id_str(user_id)
    if not oid:
        return jsonify({'error': 'Invalid user ID'}), 400

    user = users_collection.find_one({'_id': oid})
    if not user:
        return jsonify({'error': 'User not found'}), 404

    return jsonify({'user': parse_json(user)}), 200


@app.route('/api/users/<user_id>', methods=['PUT'])
def update_user(user_id):
    """Update a user profile."""
    oid = object_id_str(user_id)
    if not oid:
        return jsonify({'error': 'Invalid user ID'}), 400

    data = request.get_json()
    if not data:
        return jsonify({'error': 'No data provided'}), 400

    # Fields that can be updated
    allowed_fields = ['full_name', 'bio', 'avatar_url', 'role', 'preferences', 'social_links', 'is_active']
    update_data = {k: v for k, v in data.items() if k in allowed_fields}
    update_data['updated_at'] = datetime.utcnow()

    result = users_collection.update_one({'_id': oid}, {'$set': update_data})
    if result.matched_count == 0:
        return jsonify({'error': 'User not found'}), 404

    updated_user = users_collection.find_one({'_id': oid})
    return jsonify({'message': 'User updated successfully', 'user': parse_json(updated_user)}), 200


@app.route('/api/users/<user_id>', methods=['DELETE'])
def delete_user(user_id):
    """Delete a user profile (soft delete)."""
    oid = object_id_str(user_id)
    if not oid:
        return jsonify({'error': 'Invalid user ID'}), 400

    result = users_collection.update_one(
        {'_id': oid},
        {'$set': {'is_active': False, 'updated_at': datetime.utcnow()}}
    )
    if result.matched_count == 0:
        return jsonify({'error': 'User not found'}), 404

    return jsonify({'message': 'User deactivated successfully'}), 200


# ==================== DOCUMENT ENDPOINTS ====================

@app.route('/api/documents', methods=['POST'])
def create_document():
    """Create a new document in the CMS."""
    data = request.get_json()
    if not data:
        return jsonify({'error': 'No data provided'}), 400

    required_fields = ['title', 'content', 'author_id']
    for field in required_fields:
        if field not in data:
            return jsonify({'error': f'Missing required field: {field}'}), 400

    author_oid = object_id_str(data['author_id'])
    if not author_oid:
        return jsonify({'error': 'Invalid author ID'}), 400

    # Verify author exists
    author = users_collection.find_one({'_id': author_oid, 'is_active': True})
    if not author:
        return jsonify({'error': 'Author not found or inactive'}), 404

    document = {
        'title': data['title'],
        'slug': data.get('slug', data['title'].lower().replace(' ', '-')),
        'content': data['content'],
        'excerpt': data.get('excerpt', data['content'][:200] if len(data['content']) > 200 else data['content']),
        'author_id': author_oid,
        'author_name': author['full_name'],
        'category': data.get('category', 'uncategorized'),
        'tags': data.get('tags', []),
        'status': data.get('status', 'draft'),  # draft, published, archived
        'featured_image': data.get('featured_image', ''),
        'metadata': data.get('metadata', {}),
        'version': 1,
        'version_history': [],
        'comments_count': 0,
        'views_count': 0,
        'likes_count': 0,
        'created_at': datetime.utcnow(),
        'updated_at': datetime.utcnow(),
        'published_at': datetime.utcnow() if data.get('status') == 'published' else None
    }

    try:
        result = documents_collection.insert_one(document)
        document['_id'] = result.inserted_id

        # Update user's document count and tags
        users_collection.update_one(
            {'_id': author_oid},
            {
                '$inc': {'document_count': 1},
                '$addToSet': {'tags_used': {'$each': document['tags']}}
            }
        )

        return jsonify({'message': 'Document created successfully', 'document': parse_json(document)}), 201
    except Exception as e:
        return jsonify({'error': str(e)}), 500


@app.route('/api/documents', methods=['GET'])
def get_documents():
    """Query documents with various filters."""
    # Query parameters
    status = request.args.get('status')
    category = request.args.get('category')
    author_id = request.args.get('author_id')
    tag = request.args.get('tag')
    search = request.args.get('search')
    sort_by = request.args.get('sort_by', 'created_at')
    sort_order = request.args.get('sort_order', 'desc')
    page = int(request.args.get('page', 1))
    per_page = int(request.args.get('per_page', 20))
    date_from = request.args.get('date_from')
    date_to = request.args.get('date_to')

    # Build query
    query = {}
    if status:
        query['status'] = status
    if category:
        query['category'] = category
    if author_id:
        oid = object_id_str(author_id)
        if oid:
            query['author_id'] = oid
    if tag:
        query['tags'] = tag
    if search:
        query['$text'] = {'$search': search}
    if date_from or date_to:
        date_query = {}
        if date_from:
            date_query['$gte'] = datetime.fromisoformat(date_from)
        if date_to:
            date_query['$lte'] = datetime.fromisoformat(date_to)
        query['created_at'] = date_query

    # Sorting
    sort_direction = DESCENDING if sort_order == 'desc' else ASCENDING
    sort_field = sort_by if sort_by in ['created_at', 'updated_at', 'published_at', 'views_count', 'likes_count', 'title'] else 'created_at'

    skip = (page - 1) * per_page

    # Execute query
    cursor = documents_collection.find(query).sort(sort_field, sort_direction).skip(skip).limit(per_page)
    documents = list(cursor)
    total = documents_collection.count_documents(query)

    return jsonify({
        'documents': parse_json(documents),
        'total': total,
        'page': page,
        'per_page': per_page,
        'pages': (total + per_page - 1) // per_page
    }), 200


@app.route('/api/documents/<doc_id>', methods=['GET'])
def get_document(doc_id):
    """Get a single document by ID and increment view count."""
    oid = object_id_str(doc_id)
    if not oid:
        return jsonify({'error': 'Invalid document ID'}), 400

    # Increment view count
    document = documents_collection.find_one_and_update(
        {'_id': oid},
        {'$inc': {'views_count': 1}},
        return_document=True
    )
    if not document:
        return jsonify({'error': 'Document not found'}), 404

    return jsonify({'document': parse_json(document)}), 200


@app.route('/api/documents/<doc_id>', methods=['PUT'])
def update_document(doc_id):
    """Update a document with version tracking."""
    oid = object_id_str(doc_id)
    if not oid:
        return jsonify({'error': 'Invalid document ID'}), 400

    data = request.get_json()
    if not data:
        return jsonify({'error': 'No data provided'}), 400

    # Get current document for version history
    current_doc = documents_collection.find_one({'_id': oid})
    if not current_doc:
        return jsonify({'error': 'Document not found'}), 404

    # Save current version to history
    version_entry = {
        'version': current_doc['version'],
        'title': current_doc['title'],
        'content': current_doc['content'],
        'updated_at': current_doc['updated_at'],
        'updated_by': data.get('updated_by', str(current_doc['author_id']))
    }

    allowed_fields = ['title', 'content', 'excerpt', 'category', 'tags', 'status',
                      'featured_image', 'metadata', 'slug']
    update_data = {k: v for k, v in data.items() if k in allowed_fields}
    update_data['updated_at'] = datetime.utcnow()

    # Set published_at if status changed to published
    if data.get('status') == 'published' and current_doc.get('status') != 'published':
        update_data['published_at'] = datetime.utcnow()

    result = documents_collection.update_one(
        {'_id': oid},
        {
            '$set': update_data,
            '$inc': {'version': 1},
            '$push': {'version_history': version_entry}
        }
    )

    updated_doc = documents_collection.find_one({'_id': oid})
    return jsonify({'message': 'Document updated successfully', 'document': parse_json(updated_doc)}), 200


@app.route('/api/documents/<doc_id>', methods=['DELETE'])
def delete_document(doc_id):
    """Delete a document (archive it)."""
    oid = object_id_str(doc_id)
    if not oid:
        return jsonify({'error': 'Invalid document ID'}), 400

    document = documents_collection.find_one({'_id': oid})
    if not document:
        return jsonify({'error': 'Document not found'}), 404

    # Archive instead of hard delete
    documents_collection.update_one(
        {'_id': oid},
        {'$set': {'status': 'archived', 'updated_at': datetime.utcnow()}}
    )

    # Decrement author's document count
    users_collection.update_one(
        {'_id': document['author_id']},
        {'$inc': {'document_count': -1}}
    )

    return jsonify({'message': 'Document archived successfully'}), 200


@app.route('/api/documents/<doc_id>/like', methods=['POST'])
def like_document(doc_id):
    """Like a document."""
    oid = object_id_str(doc_id)
    if not oid:
        return jsonify({'error': 'Invalid document ID'}), 400

    result = documents_collection.update_one(
        {'_id': oid},
        {'$inc': {'likes_count': 1}}
    )
    if result.matched_count == 0:
        return jsonify({'error': 'Document not found'}), 404

    return jsonify({'message': 'Document liked'}), 200


