@app.route('/api/analytics/tag-cloud', methods=['GET'])
def tag_cloud():
    """Aggregation: Generate tag cloud data with usage counts."""
    pipeline = [
        {'$match': {'status': 'published'}},
        {'$unwind': '$tags'},
        {'$group': {
            '_id': '$tags',
            'count': {'$sum': 1},
            'total_views': {'$sum': '$views_count'},
            'total_likes': {'$sum': '$likes_count'}
        }},
        {'$sort': {'count': -1}},
        {'$limit': 50},
        {'$project': {
            'tag': '$_id',
            'count': 1,
            'total_views': 1,
            'total_likes': 1,
            '_id': 0
        }}
    ]

    results = list(documents_collection.aggregate(pipeline))
    return jsonify({'tag_cloud': parse_json(results)}), 200


@app.route('/api/analytics/monthly-publications', methods=['GET'])
def monthly_publications():
    """Aggregation: Documents published per month."""
    year = request.args.get('year')

    match_stage = {'status': 'published', 'published_at': {'$ne': None}}
    if year:
        match_stage['published_at'] = {
            '$gte': datetime(int(year), 1, 1),
            '$lt': datetime(int(year) + 1, 1, 1)
        }

    pipeline = [
        {'$match': match_stage},
        {'$group': {
            '_id': {
                'year': {'$year': '$published_at'},
                'month': {'$month': '$published_at'}
            },
            'count': {'$sum': 1},
            'total_views': {'$sum': '$views_count'},
            'total_likes': {'$sum': '$likes_count'},
            'unique_authors': {'$addToSet': '$author_id'},
            'categories': {'$addToSet': '$category'}
        }},
        {'$project': {
            '_id': 1,
            'count': 1,
            'total_views': 1,
            'total_likes': 1,
            'unique_authors_count': {'$size': '$unique_authors'},
            'categories_count': {'$size': '$categories'}
        }},
        {'$sort': {'_id.year': -1, '_id.month': -1}}
    ]

    results = list(documents_collection.aggregate(pipeline))
    return jsonify({'monthly_stats': parse_json(results)}), 200


